from collections import defaultdict

class LoopDetector:
    def __init__(self):
        self.call_counts = defaultdict(int)

    def track_call(self, component_name, query_id):
        self.call_counts[(component_name, query_id)] += 1

    def check_loops(self, query_id, max_calls=3):
        retriever_calls = self.call_counts[('retriever', query_id)]
        if retriever_calls > max_calls:
            print(f'🚨 LOOP DETECTED: Retriever called {retriever_calls} times for query {query_id}')

