from haystack.components.generators import OpenAIGenerator

class CostOptimizedGenerator(OpenAIGenerator):
    def __init__(self, **kwargs):
        super().__init__(
            model='gpt-3.5-turbo',
            max_new_tokens=150,  # Reduced from default 512+
            temperature=0.1,
            **kwargs
        )

    def run(self, prompt: str, **kwargs):
        # Truncate prompt to 2000 tokens max
        max_prompt_tokens = 2000
        words = prompt.split()
        if len(words) > max_prompt_tokens:
            prompt = ' '.join(words[-max_prompt_tokens:])

        return super().run(prompt=prompt, **kwargs)

# Usage - 70% token reduction
generator = CostOptimizedGenerator(api_key='your-key')
pipeline.replace_component('generator', generator)

from haystack import Component

class EarlyTerminator(Component):
    @Component.output_types(has_final_answer=bool)
    def run(self, documents, generation):
        if documents and documents[0].metadata.get('score', 0) > 0.85:
            return {'has_final_answer': True}

        # Check generation quality
        if generation and len(generation) > 50 and 'I don't know' not in generation.lower():
            return {'has_final_answer': True}

        return {'has_final_answer': False}

# Pipeline wiring
pipeline.connect('retriever', 'terminator')
pipeline.connect('generator', 'terminator')
pipeline.add_conditional_edges(
    'terminator', 
    has_final_answer,
    {
        True: 'formatter',
        False: 'retriever'  # Loop back
    }
)
